SELECT team_name
FROM teams
WHERE team_id IN (
    SELECT winner_id
    FROM championships
);

SELECT SUM(attendance) AS total_attendance
FROM championships
WHERE year = 2022;

SELECT championship_name
FROM championships
WHERE attendance = (SELECT MAX(attendance) FROM championships);

SELECT year, COUNT(championship_id) AS total_championships
FROM championships
GROUP BY year;

SELECT championship_name, year
FROM championships
ORDER BY year DESC;

SELECT attendance AS total_attendance
FROM championships
WHERE championship_id = 0;
